function n(){try{const t=localStorage.getItem("awosel_active_branch");if(t){const e=JSON.parse(t);if(e?.uuid)return e.uuid}}catch{}try{const t=localStorage.getItem("user");if(t){const e=JSON.parse(t);if(e?.branch_id)return e.branch_id}}catch{}try{const t=localStorage.getItem("token");if(t){const e=t.split(".");if(e.length===3){const a=JSON.parse(atob(e[1].replace(/-/g,"+").replace(/_/g,"/")));if(a?.branch_id)return a.branch_id}}}catch{}return null}function c(){try{const t=localStorage.getItem("user");if(t){const e=JSON.parse(t);if(e?.branch_id){const a=localStorage.getItem("awosel_active_branch");if(a){const r=JSON.parse(a);if((r?.id||r?.uuid)===e.branch_id)return r}return{id:e.branch_id,uuid:e.branch_id,name:e.branch_name||"My Branch"}}}}catch{}try{const t=localStorage.getItem("awosel_active_branch");if(t)return JSON.parse(t)}catch{}return null}function o(){try{const t=localStorage.getItem("user");if(t){const e=JSON.parse(t);if(e?.organization_id)return e.organization_id}}catch{}try{const t=localStorage.getItem("token");if(t){const e=t.split(".");if(e.length===3){const a=JSON.parse(atob(e[1].replace(/-/g,"+").replace(/_/g,"/")));if(a?.organization_id)return a.organization_id}}}catch{}return null}export{o as a,c as b,n as g};
